Anatomia de uma função

nome_da_funcao &lt;- function(argumento1, argumento2 = valor_default) {
  # corpo da função
  resultado &lt;- argumento1 + argumento2
  return(resultado)
}


Exemplos aplicados

# Função para área basal (m²)
area_basal &lt;- function(dap) {
  pi * (dap / 200)^2
}

area_basal(dap = 25)

[1] 0.04908739

area_basal(c(15, 20, 25, 30))

[1] 0.01767146 0.03141593 0.04908739 0.07068583



# Função para volume cilíndrico
volume &lt;- function(dap, altura, ff = 0.5) {
  area_basal(dap) * altura * ff
}

volume(25, 30)

[1] 0.7363108

volume(25, 30, ff = 0.45)

[1] 0.6626797



# Função para classificar sítio
classificar_sitio &lt;- function(altura_dominante, idade) {
  if (altura_dominante &gt; 30) return("Bom")
  if (altura_dominante &gt; 22) return("Médio")
  return("Ruim")
}

classificar_sitio(33, 7)

[1] "Bom"

classificar_sitio(25, 7)

[1] "Médio"

classificar_sitio(18, 7)

[1] "Ruim"
